package day1;

public class ConditionalStatements {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=40,b=60,c=30;
		if (a>b && a>c) {
			System.out.println(a+" Is big");
		}
		else if(b>c) {
			System.out.println(b+" Is Big");
		}else {
			System.out.println(c+" Is Big");
		}
		
		
	}

}
